// systolic_array.v — 8x8 output-stationary INT8
// FORGE · objective: power · pdk: sky130hd
`timescale 1ns/1ps
`default_nettype none

module systolic_array #(
  parameter int N  = 8,        // array dim
  parameter int IW = 8,        // operand width
  parameter int OW = 2*IW + 4  // 20-bit accumulator
)(
  input  wire                  clk,
  input  wire                  rst_n,
  input  wire                  in_valid,
  input  wire signed [IW-1:0]  a_row [N],
  input  wire signed [IW-1:0]  b_col [N],
  output reg                   out_valid,
  output reg  signed [OW-1:0]  c_mac [N][N]
);
  // A flows west->east, B flows north->south
  logic signed [IW-1:0] a_h [N][N+1];
  logic signed [IW-1:0] b_v [N+1][N];

  genvar i, j;
  generate
    for (i = 0; i < N; i++) begin : g_row
      for (j = 0; j < N; j++) begin : g_col
        pe #(.IW(IW), .OW(OW)) u_pe (
          .clk (clk), .rst_n (rst_n), .en (in_valid),
          .a_in (a_h[i][j]),  .a_out (a_h[i][j+1]),
          .b_in (b_v[i][j]),  .b_out (b_v[i+1][j]),
          .c_acc(c_mac[i][j]) );
      end
    end
  endgenerate
endmodule
